import{_ as o,o as t,c as a,a3 as d}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Email provider webhooks","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Email provider webhooks | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/email-webhooks"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Email provider webhooks | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/email-webhooks"}]]},"headers":[],"relativePath":"developer-guide/email-webhooks.md","filePath":"developer-guide/email-webhooks.md","lastUpdated":1784743690000}'),r={name:"developer-guide/email-webhooks.md"};function i(n,e,c,s,l,h){return t(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="email-provider-webhooks" tabindex="-1">Email provider webhooks <a class="header-anchor" href="#email-provider-webhooks" aria-label="Permalink to &quot;Email provider webhooks&quot;">​</a></h1><p>Inbound delivery webhooks for API mail providers (Postmark, Mailgun). SMTP / log / array / sendmail do not support webhooks.</p><h2 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scope</th><th>Method</th><th>Path</th></tr></thead><tbody><tr><td>Central</td><td><code>POST</code></td><td><code>/webhooks/email/{provider}</code></td></tr><tr><td>Tenant (custom mail)</td><td><code>POST</code></td><td><code>/webhooks/email/{provider}/{tenant}</code></td></tr></tbody></table><p><code>{provider}</code> is the driver slug (<code>postmark</code>, <code>mailgun</code>). <code>{tenant}</code> is the Stancl tenant string id (UUID).</p><p>Both routes are CSRF-exempt (<code>webhooks/email/*</code>) and rate-limited (<code>throttle:webhooks</code>).</p><h2 id="feature-flag" tabindex="-1">Feature flag <a class="header-anchor" href="#feature-flag" aria-label="Permalink to &quot;Feature flag&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env</th><th>Default</th><th>Purpose</th></tr></thead><tbody><tr><td><code>EMAIL_WEBHOOKS_ENABLED</code></td><td><code>true</code></td><td>Master switch (503 when false)</td></tr><tr><td><code>EMAIL_WEBHOOK_TOLERANCE</code></td><td><code>300</code></td><td>Mailgun signature timestamp skew (seconds)</td></tr></tbody></table><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>Central <code>system_settings</code> / Tenant <code>tenant_settings</code>:</p><table tabindex="0"><thead><tr><th>Key</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>mail_webhook_secret</code></td><td>encrypted string</td><td>Postmark Basic Auth password / Mailgun signing key</td></tr><tr><td><code>mail_webhook_events</code></td><td>JSON array</td><td>Platform event keys to process</td></tr></tbody></table><p>Admin GET settings responses include <code>meta.mail_webhook</code> with <code>webhook_url</code>, <code>available_events</code>, <code>selected_events</code>, <code>instructions</code>, and <code>has_webhook_secret</code>.</p><p>Tenant <code>mail_mode=system</code> does not expose a tenant webhook URL — configure Central.</p><h2 id="platform-event-keys" tabindex="-1">Platform event keys <a class="header-anchor" href="#platform-event-keys" aria-label="Permalink to &quot;Platform event keys&quot;">​</a></h2><p>Drivers advertise a catalog; the UI multiselect stores these keys:</p><p><code>delivered</code>, <code>bounced</code>, <code>complained</code>, <code>opened</code>, <code>clicked</code>, <code>failed</code></p><p>Defaults when unset: <code>delivered</code>, <code>bounced</code>, <code>complained</code>, <code>opened</code>, <code>clicked</code>.</p><h2 id="processing" tabindex="-1">Processing <a class="header-anchor" href="#processing" aria-label="Permalink to &quot;Processing&quot;">​</a></h2><ol><li>Resolve driver via <code>EmailDriverRegistry</code> (<code>SupportsWebhooks</code>).</li><li>Verify signature with the scoped webhook secret.</li><li>Parse provider payload → normalized events.</li><li>Filter by <code>mail_webhook_events</code>.</li><li>Match <code>CentralEmailLog</code> / <code>TenantEmailLog</code> by <code>message_id</code> and update status / <code>meta</code> (idempotent via <code>meta.webhook_event_ids</code>).</li></ol><h3 id="status-progression" tabindex="-1">Status progression <a class="header-anchor" href="#status-progression" aria-label="Permalink to &quot;Status progression&quot;">​</a></h3><p>Typical path: <code>sending</code> → <code>sent</code> → <code>delivered</code> → <code>opened</code> → <code>clicked</code>.</p><ul><li>Open/Click webhooks set status to <code>opened</code> / <code>clicked</code> (and increment <code>meta.opens</code> / <code>meta.clicks</code>).</li><li>Engagement statuses are not downgraded back to <code>delivered</code>.</li><li>Terminal statuses (<code>bounced</code>, <code>complained</code>, <code>failed</code>) are not overwritten by open/click.</li></ul><h3 id="provider-tracking-requirements" tabindex="-1">Provider tracking requirements <a class="header-anchor" href="#provider-tracking-requirements" aria-label="Permalink to &quot;Provider tracking requirements&quot;">​</a></h3><p>Selecting Open/Click in Central/Tenant settings only controls which inbound events SaleOS processes. You must also enable Open/Click on the <strong>provider webhook</strong> and turn on open/link tracking in the provider console (e.g. Postmark server tracking). Settings save does not sync checkboxes into Postmark/Mailgun.</p><h2 id="extending-a-new-provider" tabindex="-1">Extending a new provider <a class="header-anchor" href="#extending-a-new-provider" aria-label="Permalink to &quot;Extending a new provider&quot;">​</a></h2><ol><li>Implement <code>EmailDriverInterface</code> + <code>SupportsWebhooks</code>.</li><li>Register in <code>config/email.php</code> → <code>drivers</code>.</li><li>Advertise <code>webhookEvents()</code>, <code>verifySignature()</code>, <code>parseEvents()</code>, <code>setupInstructions()</code>.</li><li>No controller or UI branching on provider name is required beyond the driver catalog.</li></ol><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/developer-guide/multi-provider-email">Multi-Provider Email</a></li><li>Body logging + <a href="/developer-guide/multi-provider-email#manual-resend">manual resend</a> (same email logs surface)</li></ul>',28)])])}const u=o(r,[["render",i]]);export{m as __pageData,u as default};
